bool endOfMapp = false;
dyn_string dyn_dp = makeDynString($SetDP);
dyn_bool dp_value;

////////////////////////////////////////////////////////////////////

string OBJ_PRESS_SET1 = "obj_press_set1";

string OBJ_PRESS_SET1_MAX = "obj_press_set1_max";
string OBJ_PRESS_SET1_MIN = "obj_press_set1_min";


string OBJ_HZ_SET1 = "obj_hz_set1";

string OBJ_FAN_VIB_HILM = "obj_fan_vib_hilm";

string OBJ_AD_OPEN_TM_SET = "obj_ad_open_tm_set";
string OBJ_AD_OPEN_TMLM = "obj_ad_open_tmlm";


string OBJ_AD_OPEN_LM = "obj_ad_open_lm";

string OBJ_FAN_VIB_INVALIDITY = "obj_fan_vib_invalidity";


//н•„мҡ”м—җ мқҳн•ҙ нҺём§‘к°ҖлҠҘн•ң text к°қмІҙмқҳ valueлҘј м ҖмһҘн•ңлӢӨ.

dyn_string DYN_ALL_MAP_EDITABLE_VALUES; // DP ELEMENT к°’ EX: TI_001A.PVSOURCE -  EDIT к°ҖлҠҘ мҶҚм„ұ - л°°м—ҙм ҖмһҘ
dyn_string DYN_ALL_MAP_EDITABLE_KEYS;  // DPE Object Name - л°°м—ҙм ҖмһҘ
dyn_string DYN_ALL_MAP_EDITABLE_DESC;  // MSG BOX DESCRIPTION - TEXT OBJ - л°°м—ҙм ҖмһҘ
dyn_string DYN_ALL_INIT_INVISIBLE;  // COMBO BOX INVISIBLE - л°°м—ҙм ҖмһҘ

mapping MAP_SHAPE_TYPE;  // нҷ”л©ҙ  object type лӘ…кё° (ex : text, combo box, radio box .... л“ұл“ұ)
mapping MAP_EDITABLE_ALM;  // ALARM VALUE DPE м§Җм •
mapping MAP_EDITABLE_VALUE;  // TEXT OBJ  DPE м§Җм •
mapping MAP_ALERT_BOOL;  // BIT TYPE ALARM DPE м§Җм •
mapping MAP_READONLY_VALUE;  // READ ONLY DPE м§Җм •
mapping MAP_ALERT_PRIO;  // CASCADE OBJ - ALARM PRIO DPE м§Җм •
mapping MAP_ALERT_COMBO_PRIO;  // COMBO BOX OBJ - ALARM PRIO DPE м§Җм •
mapping MAP_EDITABLE_DESC;  // DPE Object Name м§Җм •
mapping MAP_RADIO; // мһ…л Ҙ / м„јм„ңкө¬л¶„ DPE м§Җм •
mapping MAP_CHECK; // CHECK BOX OBJECT DPE м§Җм •
mapping MAP_DEPEND_VALUE;  //мқҳмЎҙм„ұмқҙ мһҲлҠ” кІҪмҡ° : мҲҳлҸҷ лӘЁл“ң мқјл•Ң мҲҳлҸҷк°’ н•„л“ңк°Җ ONлҗҳлҠ” кІҪмҡ°
mapping MAP_VALUE_BOOL;        // BIT TYPE VALUE DPE м§Җм •

void MAPP(dyn_string dyn_dp)
{
  //MAPP н•ЁмҲҳм—җм„ң initialм—җм„ң м •мқҳлҗң dpлҘј mappingн•ңлӢӨ.
  //dpк°Җ nк°ңмқҙл©ҙ dp1,dp2,.....,dpn
  //dpк°Җ 1к°ңмқҙл©ҙ dp мңјлЎң м •мқҳн•ңлӢӨ.
  //нҢҢлқјлҜён„° мһҘмқҳ мҲңм„ңлҢҖлЎң м „мІҙ л°°м—ҙмқ„ м ҖмһҘн•ңлӢӨ. мҲңм„ң мЈјмқҳ!!
  // mappingмқҖ л¬ҙмһ‘мң„мҲңм„ңмқҙлӢӨ.мһ…л Ҙн•ңлҢҖлЎң л“Өм–ҙк°Җкұ°лӮҳ мЎ°нҡҢлҗҳм§Җ м•ҠмқҢ.

  string dp,caption;
  dp = dyn_dp[1];

  //shape type map  - SWICH CASE л¬ё мӮ¬мҡ© / м Ғмҡ©лІ„нҠј
  MAP_SHAPE_TYPE["TEXT_FIELD"] = 1;
  MAP_SHAPE_TYPE["COMBO_BOX"] = 2;
  MAP_SHAPE_TYPE["RADIO_BOX"] = 3;
  MAP_SHAPE_TYPE["CASCADE_BOX"] = 4;
  MAP_SHAPE_TYPE["CHECK_BOX"] = 5;

  MAP_READONLY_VALUE[OBJ_AD_OPEN_TMLM] = dp + ".value.AD_OPEN_TMLM";
//   MAP_READONLY_VALUE[OBJ_FAN_CHECK_DLY_TM_SET] = dp + ".cmd.FAN_CHECK_DLY_TM_SET";
//   MAP_READONLY_VALUE[OBJ_FAN_CHECK_DLY_TM] = dp + ".value.FAN_CHECK_DLY_TM";

  MAP_EDITABLE_VALUE[OBJ_PRESS_SET1] = dp + ".cmd.PRESS_SP";
  MAP_EDITABLE_DESC[OBJ_PRESS_SET1] = "м„Өм •м••л Ҙ";
  dynAppend(DYN_ALL_MAP_EDITABLE_KEYS,OBJ_PRESS_SET1);

  MAP_EDITABLE_VALUE[OBJ_PRESS_SET1_MAX] = dp + ".cmd.PRESS_MAX";
  MAP_EDITABLE_DESC[OBJ_PRESS_SET1_MAX] = "м„Өм •м••л Ҙ Max";
  dynAppend(DYN_ALL_MAP_EDITABLE_KEYS,OBJ_PRESS_SET1_MAX);

  MAP_EDITABLE_VALUE[OBJ_PRESS_SET1_MIN] = dp + ".cmd.PRESS_MIN";
  MAP_EDITABLE_DESC[OBJ_PRESS_SET1_MIN] = "м„Өм •м••л Ҙ Min";
  dynAppend(DYN_ALL_MAP_EDITABLE_KEYS,OBJ_PRESS_SET1_MIN);

  MAP_EDITABLE_VALUE[OBJ_HZ_SET1] = dp + ".cmd.HZ_SP";
  MAP_EDITABLE_DESC[OBJ_HZ_SET1] = "м„Өм •Hz";
  dynAppend(DYN_ALL_MAP_EDITABLE_KEYS,OBJ_HZ_SET1);

  MAP_EDITABLE_VALUE[OBJ_FAN_VIB_HILM] = dp + ".cmd.FAN_VIB_HILM";
  MAP_EDITABLE_DESC[OBJ_FAN_VIB_HILM] = "Fan vibration high limit";
  dynAppend(DYN_ALL_MAP_EDITABLE_KEYS,OBJ_FAN_VIB_HILM);

  MAP_EDITABLE_VALUE[OBJ_AD_OPEN_TM_SET] = dp + ".cmd.AD_OPEN_SETTM";
  MAP_EDITABLE_DESC[OBJ_AD_OPEN_TM_SET] = "Auto Damper Open Time Set";
  dynAppend(DYN_ALL_MAP_EDITABLE_KEYS,OBJ_AD_OPEN_TM_SET);

  MAP_EDITABLE_VALUE[OBJ_AD_OPEN_LM] = dp + ".cmd.AD_OPEN_LM";
  MAP_EDITABLE_DESC[OBJ_AD_OPEN_LM] = "Auto Damper Open Limit";
  dynAppend(DYN_ALL_MAP_EDITABLE_KEYS,OBJ_AD_OPEN_LM);

    /* check box */
//   MAP_CHECK[OBJ_AUTO_SEL1] = dp + ".cmd.AUTOSEL.SEL1";
//   MAP_EDITABLE_DESC[OBJ_AUTO_SEL1] = "1нҳёкё° PRESS AUTO BACKUP";
//   dynAppend(DYN_ALL_MAP_EDITABLE_KEYS,OBJ_AUTO_SEL1);
//
//   MAP_CHECK[OBJ_AUTO_SEL2] = dp + ".cmd.AUTOSEL.SEL2";
//   MAP_EDITABLE_DESC[OBJ_AUTO_SEL2] = "2нҳёкё° PRESS AUTO BACKUP";
//   dynAppend(DYN_ALL_MAP_EDITABLE_KEYS,OBJ_AUTO_SEL2);
//
//   MAP_CHECK[OBJ_AUTO_SEL3] = dp + ".cmd.AUTOSEL.SEL3";
//   MAP_EDITABLE_DESC[OBJ_AUTO_SEL3] = "3нҳёкё° PRESS AUTO BACKUP";
//   dynAppend(DYN_ALL_MAP_EDITABLE_KEYS,OBJ_AUTO_SEL3);
//
//   MAP_CHECK[OBJ_AUTO_SEL4] = dp + ".cmd.AUTOSEL.SEL4";
//   MAP_EDITABLE_DESC[OBJ_AUTO_SEL4] = "4нҳёкё° PRESS AUTO BACKUP";
//   dynAppend(DYN_ALL_MAP_EDITABLE_KEYS,OBJ_AUTO_SEL4);
//
//   MAP_CHECK[OBJ_AUTO_SEL5] = dp + ".cmd.AUTOSEL.SEL5";
//   MAP_EDITABLE_DESC[OBJ_AUTO_SEL5] = "5нҳёкё° PRESS AUTO BACKUP";
//   dynAppend(DYN_ALL_MAP_EDITABLE_KEYS,OBJ_AUTO_SEL5);


  MAP_CHECK[OBJ_FAN_VIB_INVALIDITY] = dp + ".cmd.FAN_VIB_INVALIDITY";
  MAP_EDITABLE_DESC[OBJ_FAN_VIB_INVALIDITY] = "FAN Invalidity";
  dynAppend(DYN_ALL_MAP_EDITABLE_KEYS,OBJ_FAN_VIB_INVALIDITY);


   /* л°°м—ҙмқҳ keyк°’мқ„ кё°мӨҖмңјлЎң dyn value/desc л°°м—ҙ мһ‘м„ұ */
  string map_value;
  string map_key;
  bool bool_haskey;
  for(int i=1;i<=dynlen(DYN_ALL_MAP_EDITABLE_KEYS);i++)
  {
    map_key = DYN_ALL_MAP_EDITABLE_KEYS[i];


    //м•ҢлһҢ Prioм„Өм •
    bool_haskey = mappingHasKey(MAP_ALERT_COMBO_PRIO,map_key);
    if(bool_haskey)
    {
      map_value = MAP_ALERT_COMBO_PRIO[map_key];
      dynAppend(DYN_ALL_MAP_EDITABLE_VALUES,map_value);
      dynAppend(DYN_ALL_MAP_EDITABLE_DESC,MAP_EDITABLE_DESC[map_key]);
      continue;
    }

    //кё°нғҖ м„Өм •к°’
    bool_haskey = mappingHasKey(MAP_EDITABLE_VALUE,map_key);
    if(bool_haskey)
    {
      map_value = MAP_EDITABLE_VALUE[map_key];
      dynAppend(DYN_ALL_MAP_EDITABLE_VALUES,map_value);
      dynAppend(DYN_ALL_MAP_EDITABLE_DESC,MAP_EDITABLE_DESC[map_key]);
      continue;
    }

    // cascade м•ҢлһҢ prio
    bool_haskey = mappingHasKey(MAP_ALERT_PRIO,map_key);
    if(bool_haskey)
    {
      map_value = MAP_ALERT_PRIO[map_key];
      dynAppend(DYN_ALL_MAP_EDITABLE_VALUES,map_value);
      dynAppend(DYN_ALL_MAP_EDITABLE_DESC,MAP_EDITABLE_DESC[map_key]);
      continue;
    }

    // check box
    bool_haskey = mappingHasKey(MAP_CHECK,map_key);
    if(bool_haskey)
    {
      map_value = MAP_CHECK[map_key];
      dynAppend(DYN_ALL_MAP_EDITABLE_VALUES,map_value);
      dynAppend(DYN_ALL_MAP_EDITABLE_DESC,MAP_EDITABLE_DESC[map_key]);
      continue;
    }

    // radio button
    bool_haskey = mappingHasKey(MAP_RADIO,map_key);
    if(bool_haskey)
    {
      map_value = MAP_RADIO[map_key];
      dynAppend(DYN_ALL_MAP_EDITABLE_VALUES,map_value);
      dynAppend(DYN_ALL_MAP_EDITABLE_DESC,MAP_EDITABLE_DESC[map_key]);
      continue;
    }
  }
  endOfMapp = true;//Mapping мҷ„лЈҢ мІҙнҒ¬
}


