{
  if(mode1 == 1)
  {
      dp_value[1] = 1;
      dp_value[2] = 0;
      dp_value[3] = 0;
      dp_value[4] = 0;
      dp_value[5] = 0;
  }
  else if(mode2 == 1)
  {
      dp_value[1] = 0;
      dp_value[2] = 1;
      dp_value[3] = 0;
      dp_value[4] = 0;
      dp_value[5] = 0;
  }
  else if(mode3 == 1)
  {
      dp_value[1] = 0;
      dp_value[2] = 0;
      dp_value[3] = 1;
      dp_value[4] = 0;
      dp_value[5] = 0;
  }
  else if(mode4 == 1)
  {
      dp_value[1] = 0;
      dp_value[2] = 0;
      dp_value[3] = 0;
      dp_value[4] = 1;
      dp_value[5] = 0;
  }
  else if(mode5 == 1)
  {
      dp_value[1] = 0;
      dp_value[2] = 0;
      dp_value[3] = 0;
      dp_value[4] = 0;
      dp_value[5] = 1;
  }
  else
  {
      dp_value[1] = 0;
      dp_value[2] = 0;
      dp_value[3] = 0;
      dp_value[4] = 0;
      dp_value[5] = 0;
  }
  setValue("obj_auto_sel1","state",0,dp_value[1]);
  setValue("obj_auto_sel2","state",0,dp_value[2]);
  setValue("obj_auto_sel3","state",0,dp_value[3]);
  setValue("obj_auto_sel4","state",0,dp_value[4]);
  setValue("obj_auto_sel5","state",0,dp_value[5]);
